import{_ as a,c as r,o as i,ah as l}from"./chunks/framework.DaDXF32t.js";const o="/assets/static_feature_example.CAcTrlyW.png",t="/assets/static_feature_example2.Cn0l3y-m.png",s="/assets/swipe_example_common_shop.BLBg_yLg.png",c="/assets/swipe_example_create.BjM5VwCS.png",n="/assets/swipe_example_preset.CabisMW5.png",p="/assets/swipe_example_activity.BymYG7rI.png",x=JSON.parse('{"title":"图像识别","description":"","frontmatter":{},"headers":[],"relativePath":"develop_doc/script/game_feature.md","filePath":"develop_doc/script/game_feature.md","lastUpdated":1774428637000}'),_={name:"develop_doc/script/game_feature.md"};function g(d,e,h,m,u,f){return i(),r("div",null,e[0]||(e[0]=[l('<h1 id="图像识别" tabindex="-1">图像识别 <a class="header-anchor" href="#图像识别" aria-label="Permalink to “图像识别”">​</a></h1><p>主要方法:</p><ol><li><a href="#模板匹配">模板匹配</a><ul><li>对应文件路径 : <code>&quot;core/image.py&quot;</code></li></ul></li><li><a href="#比较像素值">比较像素值</a><ul><li>对应文件路径 : <code>&quot;core/color.py&quot;</code></li></ul></li><li><a href="/develop_doc/script/ocr.html">OCR</a></li><li>TODO:: yolo目标检测</li></ol><h2 id="模板匹配" tabindex="-1">模板匹配 <a class="header-anchor" href="#模板匹配" aria-label="Permalink to “模板匹配”">​</a></h2><ul><li><strong>description</strong>: 在<code>BAAS</code>中, 我们通常使用模板匹配识别游戏中静态的图像, 例如一些<strong>按钮</strong>, <strong>图标</strong>, 对于此类目标, 模板匹配能够在 1ms 内完成定位，且无需GPU资源，远快于深度学习模型。因此，在这种场景下，请使用模板匹配。</li><li><strong>related docs</strong>: 阅读以下例子可以帮助你理解模板匹配的使用场景和方法 <ol><li><a href="https://docs.opencv.org/4.x/d4/dc6/tutorial_py_template_matching.html" target="_blank" rel="noreferrer">OpenCV官方文档模板匹配例子</a></li><li><a href="https://docs.opencv.org/4.x/df/dfb/group__imgproc__object.html#ga586ebfb0a7fb604b35a23d85391329be" target="_blank" rel="noreferrer">cv2.matchTemplate函数原型</a></li></ol></li><li><strong>pros</strong>: <ol><li>计算效率高：基于滑动窗口与相关系数计算，在CPU上即可实现毫秒级响应，满足实时性要求。</li><li>静态图像识别精确度高：</li></ol></li><li><strong>cons</strong>: <ol><li>对缩放与旋转敏感：模板与待搜索图像的尺寸、方向必须严格一致，缩放或旋转将导致匹配失败。</li><li>对光照与噪声敏感：光照变化或噪声会显著降低匹配置信度。</li></ol></li></ul><p><code>BAAS</code>中实际应用场景:</p><ul><li><p>场景1 : <code>BAAS</code>如何判别是否到达商店界面</p><ul><li>下图为游戏商店截图, 红色方框内的元素都是这个页面<strong>固定不变</strong>的元素, 当模板匹配函数认定这些元素存在时, 程序认定抵达商店界面</li><li><img src="'+o+'" alt="img"></li><li><strong>note</strong>: 对于这种场景, 我们采集固定的模板图像,并记录采集区域, 在识别时, 将截图中的对应区域与模板图像进行匹配, 高于预设阈值时认为匹配成功, 程序也就知道了目前在商店界面</li><li><strong>related functions</strong>: <ol><li><a href="#compare-image"><code>compare_image</code></a></li></ol></li></ul></li><li><p>场景2 : <code>BAAS</code> 如何切换到某个具体商店页面</p><ul><li>如图绿框中的商店名称, 会随着用户滑动左侧栏而上下平移, 但是图标本体并不会发生变化, 可以使用模板匹配判断目标商店图标是否出现, 出现坐标在哪</li><li><img src="'+t+'" alt="img"></li><li><strong>note</strong>: 由于模板图像在截图中的位置不固定, 我们需要在它可出现区域内进行模板匹配, 获取最高的匹配度, 从而判断是否出现</li><li><strong>related functions</strong>: <ol><li><a href="#search-in-area"><code>search_in_area</code></a></li><li><a href="#search-image-in-area"><code>search_image_in_area</code></a></li><li><a href="#get-image-all-appear-position"><code>get_image_all_appear_position</code></a></li></ol></li></ul></li></ul><p>有关滑动（swipe）</p><ol><li>BAAS 大部分滑动都是默认会滑动到理想的位置, 即没有做检测的, 由于不同用户电脑性能不同, 这会导致滑动不到位的问题 <a href="https://github.com/pur1fying/blue_archive_auto_script/issues/98" target="_blank" rel="noreferrer">#98</a></li><li>滑动时我们希望: <ul><li>检测本次滑动导致 y 平移多少像素 <ol><li>普通商店中, 我们在检测商品时需要下滑商品界面 <a href="https://github.com/pur1fying/blue_archive_auto_script/blob/master/module/shop/common_shop.py#L78" target="_blank" rel="noreferrer">(相关代码)</a><ul><li><img src="'+s+'" alt="img"></li></ul></li><li>制造中, 我们在选择制造投入物资时需要下滑物资界面 <a href="https://github.com/pur1fying/blue_archive_auto_script/blob/master/module/create.py#L807" target="_blank" rel="noreferrer">(相关代码)</a><ul><li><img src="'+c+'" alt="img"></li></ul></li></ol></li><li>滑动直至某一个图像特征出现 <ol><li>在使用预设配队时, 我们希望得知滑动后需要选择的预设队伍编号是否出现 <ul><li><img src="'+n+'" alt="img"></li></ul></li><li>在活动图自动推图时, 我们希望知道滑动后目标关卡ID是否出现 <ul><li><img src="'+p+'" alt="img"></li></ul></li></ol><ul><li><strong>note</strong>: 对于这种场景, <strong>BAAS</strong>提供了<a href="#swipe-search-target-str"><code>swipe_search_target_str</code></a>函数,</li></ul></li></ul></li></ol><h2 id="比较像素值" tabindex="-1">比较像素值 <a class="header-anchor" href="#比较像素值" aria-label="Permalink to “比较像素值”">​</a></h2><h2 id="相关函数列表" tabindex="-1">相关函数列表 <a class="header-anchor" href="#相关函数列表" aria-label="Permalink to “相关函数列表”">​</a></h2><p><strong>note</strong>: 请阅读源码<code>&quot;core/image.py&quot;</code></p><h3 id="compare-image" tabindex="-1"><code>compare_image</code> <a class="header-anchor" href="#compare-image" aria-label="Permalink to “compare_image”">​</a></h3><p><strong>description</strong> : 将截图中的某个区域与目标图像进行模板匹配, 返回匹配度</p><h3 id="search-in-area" tabindex="-1"><code>search_in_area</code> <a class="header-anchor" href="#search-in-area" aria-label="Permalink to “search_in_area”">​</a></h3><p><strong>description</strong> : 在截图的某个区域内搜索模板图像, 返回匹配度最高的坐标位置和匹配度</p><h3 id="search-image-in-area" tabindex="-1"><code>search_image_in_area</code> <a class="header-anchor" href="#search-image-in-area" aria-label="Permalink to “search_image_in_area”">​</a></h3><p><strong>description</strong> : 在截图的某个区域内搜索目标图像, 返回匹配度最高的坐标位置和匹配度 <strong>note</strong> : 与<a href="#search-in-area"><code>search_in_area</code></a>不同的是, 本函数需要在运行时截图并提供模板图像, 而前者从预设的模板寻找图像</p><h3 id="get-image-all-appear-position" tabindex="-1"><code>get_image_all_appear_position</code> <a class="header-anchor" href="#get-image-all-appear-position" aria-label="Permalink to “get_image_all_appear_position”">​</a></h3><p><strong>description</strong> : 在截图的某个区域内搜索目标图像, 返回所有匹配度高于阈值的坐标位置</p><h3 id="swipe-search-target-str" tabindex="-1"><code>swipe_search_target_str</code> <a class="header-anchor" href="#swipe-search-target-str" aria-label="Permalink to “swipe_search_target_str”">​</a></h3><p><strong>description</strong> : 滑动搜索目标字符串, 直到找到, 返回目标字符串坐标</p>',22)]))}const k=a(_,[["render",g]]);export{x as __pageData,k as default};
